namespace FlowerHouse.Admin.Models.Products;
public class ProductDto { public Guid Id { get; set; } public string Name { get; set; } = ""; public string Slug { get; set; } = ""; public string? Description { get; set; } public decimal Price { get; set; } public decimal? BasePrice { get => Price; set => Price = value ?? 0; } public decimal? DiscountPrice { get; set; } public string CategoryName { get; set; } = ""; public int CategoryId { get; set; } public List<string> Tags { get; set; } = []; public List<string> FlowerTypes { get => Tags; set => Tags = value ?? []; } public List<string> Occasions { get; set; } = []; public List<ProductImageDto> Images { get; set; } = []; public bool IsActive { get; set; } = true; public bool DeliverToday { get; set; } public string? Occasion { get => Occasions.FirstOrDefault(); set => Occasions = string.IsNullOrWhiteSpace(value) ? [] : [value]; } public string? Freshness { get; set; } public string? Kind { get; set; } public string? Packaging { get; set; } public List<ProductSizeDto>? Sizes { get; set; } public DateTime CreatedAt { get; set; } }
